#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-03

# StatusLine context writer — bridges context_window.used_percentage to prompt hooks
#
# CC's StatusLine receives JSON on stdin with context_window.used_percentage.
# This script:
#   1. Reads stdin JSON
#   2. Extracts context_window.used_percentage and session_id
#   3. Writes percentage to {tmpdir}/ork-ctx-pct-{session_id}.txt
#   4. Outputs normal StatusLine text to stdout
#
# Bridge pattern: StatusLine → temp file → context-exhaustion-warner.ts (prompt hook)

set -uo pipefail

# Restrict temp file permissions to owner-only (prevent information leak on multi-user systems)
umask 077

# Read entire stdin into variable
INPUT=$(cat)

# Check jq availability — required for JSON extraction
if ! command -v jq &>/dev/null; then
  BRANCH=$(git branch --show-current 2>/dev/null || echo 'no-git')
  echo "ork | ${BRANCH} | ctx unavailable (no jq)"
  exit 0
fi

# Extract context percentage and session ID (default to 0 / empty if missing)
CTX_PCT=$(echo "$INPUT" | jq -r '.context_window.used_percentage // 0' 2>/dev/null || echo "0")
SESSION_ID=$(echo "$INPUT" | jq -r '.session_id // ""' 2>/dev/null || echo "")

# Use $TMPDIR for cross-platform temp dir (defaults to /tmp on macOS/Linux)
TMPDIR="${TMPDIR:-/tmp}"

# Write context percentage to temp file (only if we have a safe session ID)
# Validate session_id: only allow alphanumeric, dots, hyphens, underscores
if [[ -n "$SESSION_ID" && "$SESSION_ID" =~ ^[a-zA-Z0-9._-]+$ ]]; then
  echo "$CTX_PCT" > "${TMPDIR}/ork-ctx-pct-${SESSION_ID}.txt" 2>/dev/null || true
fi

# Output normal StatusLine text (same as the original inline command)
VERSION=$(jq -r .version package.json 2>/dev/null || echo '?')
BRANCH=$(git branch --show-current 2>/dev/null || echo 'no-git')
UNCOMMITTED=$(git status --porcelain 2>/dev/null | wc -l | tr -d ' ')

echo "ork v${VERSION} | ${BRANCH} | ${UNCOMMITTED} uncommitted | ctx ${CTX_PCT}%"
